mapper.sql:
FROM t_goods g
LEFT JOIN t_goods_sku gs ON gs.goods_id = g.id AND 
LEFT JOIN t_goods_image gi ON gi.sku_id = gs.id AND 
LEFT JOIN t_brand b ON b.id = g.brand_id AND 
LEFT JOIN t_series s ON s.id = g.series_id AND 
LEFT JOIN t_category c ON c.id = g.category_id AND 
LEFT JOIN t_maker m ON m.id = g.maker_id AND 
WHERE 


        AND g.name LIKE CONCAT('%', #{q.name}, '%')


        AND g.english_name LIKE CONCAT('%', #{q.englishName}, '%')


        AND g.brand_id = #{q.brandId}


        AND g.series_id = #{q.seriesId}


        AND g.category_id = #{q.categoryId}


        AND g.maker_id = #{q.makerId}


        AND EXISTS (
            SELECT 1
            FROM t_stock st
            WHERE st.goods_id = g.id
              AND 
              AND st.warehouse_id = #{q.warehouseId}
        )


        AND g.is_hot = #{q.isHot}


        AND g.sort = #{q.sort}


        AND g.status = #{q.status}


        AND gs.id = #{q.skuId}


        AND gs.sku_code LIKE CONCAT('%', #{q.skuCode}, '%')


        AND gs.sku_name LIKE CONCAT('%', #{q.skuName}, '%')
